-- ============================================
-- 约翰·博格名言
-- ============================================

INSERT OR IGNORE INTO quotes (id, content_cn, content_en, master_id, source, source_year, is_featured) VALUES
('eq-j001', '对于大多数投资者来说，指数基金是唯一理性的投资选择。', 'For most investors, index funds are the only rational investment choice.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j002', '不要试图战胜市场，市场就是市场。', 'Do not try to beat the market; the market is the market.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j003', '低成本是决定基金长期回报的关键因素。', 'Low cost is the key factor determining long-term fund returns.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j004', '时间是你最大的敌人，也是你最大的朋友。', 'Time is your greatest enemy, and also your greatest friend.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j005', '基金行业的商业模式是建立在投资者亏钱的基础上的。', 'The mutual fund industry business model is built on investors losing money.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j006', '如果你不能控制成本，你就不能控制回报。', 'If you cannot control costs, you cannot control returns.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j007', '在投资的游戏中，成本是确定的，回报是不确定的。', 'In the investment game, costs are certain, returns are uncertain.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j008', '指数基金的革命性在于它承认你无法战胜市场。', 'The revolution of index funds lies in its acknowledgment that you cannot beat the market.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j009', '基金持有人的最大敌人是基金业本身。', 'The biggest enemy of fund holders is the fund industry itself.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j010', '选择一个低成本指数基金，然后坚持到底。', 'Choose a low-cost index fund and stick with it.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j011', '投资的回报来自于经济增长和企业盈利，而不是基金经理的能力。', 'Investment returns come from economic growth and corporate earnings, not from fund managers abilities.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j012', '在长期投资中，成本的重要性超过了一切。', 'In long-term investing, the importance of costs exceeds everything.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j013', '主动管理基金的失败是系统性、结构性的，不是偶然的。', 'The failure of active fund management is systemic and structural, not accidental.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j014', '不要相信那些声称能够战胜市场的基金经理。', 'Do not believe fund managers who claim they can beat the market.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j015', '指数基金让普通投资者能够以低成本获得市场回报。', 'Index funds allow ordinary investors to get market returns at low cost.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j016', '在投资中，简单是最好的策略。', 'In investing, simplicity is the best strategy.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j017', '投资的真谛是承担市场风险，获得市场回报。', 'The essence of investing is taking market risk to get market returns.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j018', '不要试图在时机的选择上浪费时间，没有人有这个能力。', 'Do not waste time trying to time the market; no one has that ability.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j019', '基金行业的营销部门往往比投资部门更强大。', 'The mutual fund industry marketing department is often more powerful than the investment department.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j020', '在一个竞争激烈的市场中，战胜市场是不可能的。', 'In a highly competitive market, beating the market is impossible.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j021', '投资者应该专注于降低投资成本，而不是寻找更好的投资机会。', 'Investors should focus on reducing investment costs, not on finding better investment opportunities.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j022', '指数基金是民主化投资的工具。', 'Index funds are tools for democratizing investing.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j023', '大多数投资者应该投资债券和股票指数基金。', 'Most investors should invest in bond and stock index funds.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j024', '投资的四定律：低成本、分散投资、定期定投、长期持有。', 'The four laws of investing: low cost, diversification, dollar-cost averaging, long-term holding.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j025', '在一个完全有效的市场中，指数基金是最优选择。', 'In a perfectly efficient market, index funds are the optimal choice.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j026', '投资者应该抵制住追逐热门基金的诱惑。', 'Investors should resist the temptation to chase hot funds.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j027', '长期来看，主动管理基金几乎总是输给被动指数基金。', 'In the long run, active funds almost always lose to passive index funds.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j028', '不要被基金的过去业绩所迷惑。', 'Do not be fooled by a funds past performance.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j029', '投资回报等于市场回报减去成本。', 'Investment return equals market return minus cost.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j030', '投资者应该把注意力放在长期目标上，而不是短期波动。', 'Investors should focus on long-term goals, not short-term fluctuations.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j031', '复利的力量是惊人的，但成本会侵蚀大部分收益。', 'The power of compounding is amazing, but costs erode most of the gains.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j032', '低成本是投资者唯一可以控制的变量。', 'Low cost is the only variable that investors can control.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j033', '基金行业的秘密是：它为投资者创造的价值远低于它收取的费用。', 'The mutual fund industry secret is: it creates far less value for investors than the fees it charges.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j034', '在投资中，简单的解决方案往往比复杂的更好。', 'In investing, simple solutions are often better than complex ones.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j035', '投资者应该避免那些高换手率的基金。', 'Investors should avoid funds with high turnover rates.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j036', '指数化投资是长期投资成功的秘诀。', 'Index investing is the secret to long-term investment success.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j037', '不要相信那些声称能够预测市场的顾问。', 'Do not believe advisors who claim to be able to predict the market.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j038', '投资者应该把时间和精力放在资产配置上，而不是选择基金上。', 'Investors should focus their time and energy on asset allocation, not on fund selection.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j039', '低成本指数基金是大多数投资者最好的选择。', 'Low-cost index funds are the best choice for most investors.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j040', '在投资中，耐心和纪律是成功的关键。', 'In investing, patience and discipline are the keys to success.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j041', '基金行业收取的费用远超过它提供的价值。', 'The mutual fund industry charges far more than the value it provides.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j042', '投资者应该相信市场，而不是相信基金经理。', 'Investors should believe in the market, not in fund managers.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j043', '在一个竞争激烈的市场中，低成本是唯一的优势。', 'In a competitive market, low cost is the only advantage.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j044', '指数基金让投资变得简单、便宜、有效。', 'Index funds make investing simple, cheap, and efficient.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j045', '投资者应该避免追逐过去业绩最好的基金。', 'Investors should avoid chasing funds with the best past performance.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j046', '在长期投资中，成本比时机更重要。', 'In long-term investing, cost is more important than timing.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j047', '被动投资是长期投资成功的最佳策略。', 'Passive investing is the best strategy for long-term investment success.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j048', '不要被花哨的投资策略所迷惑，简单往往更好。', 'Do not be fooled by fancy investment strategies; simple is often better.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j049', '投资的本质是获得经济增长带来的收益。', 'The essence of investing is to obtain returns from economic growth.', 'm-bogle', '共同基金常识', 1999, 0),
('eq-j050', '指数基金是投资民主化的最大成就。', 'Index funds are the greatest achievement of investment democratization.', 'm-bogle', '共同基金常识', 1999, 0);

