-- 杰西·利弗莫尔名言
-- ============================================

INSERT OR IGNORE INTO quotes (id, content_cn, content_en, master_id, source, source_year, is_featured) VALUES
('eq-v001', '市场永远不会错，只有市场参与者的看法会错。', 'The market is never wrong; only market participants views can be wrong.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v002', '赚大钱不是靠交易技巧，而是靠坐着不动。', 'Making big money is not about trading skill, but about sitting still.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v003', '在市场确认趋势之前，不要急于行动。', 'Before the market confirms the trend, do not rush to act.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v004', '我的亏损教会了我很多东西。', 'My losses have taught me a lot.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v005', '永远不要在错误的时候加仓。', 'Never add to a losing position.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v006', '时机就是一切。', 'Timing is everything.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v007', '在市场开始上涨之前，价格已经在底部徘徊很久了。', 'Before the market starts rising, prices have been hovering at the bottom for a long time.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v008', '不要试图猜测市场将要做什么，而是等待市场告诉你。', 'Do not try to guess what the market will do; wait for the market to tell you.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v009', '耐心等待是交易中最重要的品质。', 'Patience is the most important quality in trading.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v010', '在股票市场上，没有人能赢过所有的人。', 'In the stock market, no one can beat everyone.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v011', '跟随趋势交易，直到趋势反转。', 'Follow the trend until the trend reverses.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v012', '亏损的原因往往是过早地买入或卖出。', 'The cause of losses is often buying or selling too early.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v013', '在市场确认方向之前保持观望。', 'Stay on the sidelines until the market confirms direction.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v014', '成功交易的秘诀是知道什么时候退出。', 'The secret to successful trading is knowing when to exit.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v015', '不要听别人的建议，坚持自己的判断。', 'Do not listen to others advice; stick to your own judgment.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v016', '在交易中，最重要的不是买什么，而是什么时候买。', 'In trading, the most important thing is not what to buy, but when to buy.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v017', '学会亏钱和学会赚钱一样重要。', 'Learning to lose money is as important as learning to make money.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v018', '在交易中，情绪是最大的敌人。', 'In trading, emotions are the biggest enemy.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v019', '不要试图抄底或逃顶。', 'Do not try to pick bottoms or tops.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v020', '市场的行为是由人性决定的。', 'Market behavior is determined by human nature.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v021', '永远不要逆势交易。', 'Never trade against the trend.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v022', '在交易中，资金管理是最重要的。', 'In trading, money management is the most important.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v023', '当你亏损时，减少交易量。', 'When you are losing, reduce trading volume.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v024', '在市场证明你正确之前，不要加仓。', 'Do not add to a position until the market proves you right.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v025', '交易的艺术在于知道什么时候持有，什么时候卖出。', 'The art of trading is knowing when to hold and when to sell.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v026', '在投机市场，没有什么是确定的。', 'In the speculative market, nothing is certain.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v027', '在市场恐慌时买入，在市场兴奋时卖出。', 'Buy when the market panics, sell when the market is excited.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v028', '成功的交易者知道什么时候应该休息。', 'Successful traders know when they should take a break.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v029', '不要爱上你的头寸。', 'Do not fall in love with your positions.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v030', '交易记录是最好的老师。', 'Trading records are the best teachers.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v031', '在交易中，止损是最重要的纪律。', 'In trading, stop-loss is the most important discipline.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v032', '市场趋势一旦形成，往往会持续一段时间。', 'Once a market trend forms, it tends to continue for some time.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v033', '不要因为股价低就买入。', 'Do not buy just because the stock price is low.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v034', '成功的交易需要耐心、勇气和纪律。', 'Successful trading requires patience, courage, and discipline.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v035', '在交易中，不要追求完美，而是追求一致。', 'In trading, do not pursue perfection, pursue consistency.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v036', '市场的记忆是短暂的，机会会不断重复。', 'The markets memory is short; opportunities keep repeating.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v037', '不要把运气当作技能。', 'Do not mistake luck for skill.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v038', '在交易中，最重要的不是你的看法对不对，而是你错了怎么办。', 'In trading, the most important thing is not whether your view is right, but what you do when you are wrong.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v039', '学会在错误中生存是成功交易的关键。', 'Learning to survive mistakes is the key to successful trading.', 'm-livermore', '股票大作手回忆录', 1923, 0),
('eq-v040', '市场的波动创造了盈利的机会。', 'Market volatility creates profit opportunities.', 'm-livermore', '股票大作手回忆录', 1923, 0);

